package org.eclipse.rdf4j.sail.lmdb;

import static org.assertj.core.api.Assertions.assertThat;

import java.io.File;
import java.util.ArrayList;
import java.util.List;

import org.eclipse.rdf4j.common.order.StatementOrder;
import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Statement;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.sail.lmdb.TxnManager.Txn;
import org.eclipse.rdf4j.sail.lmdb.config.LmdbStoreConfig;
import org.eclipse.rdf4j.sail.lmdb.model.LmdbValue;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

/**
 * Tests for the advisory seek support of {@link LmdbStatementIterator}: the miss-run counter that decides when a real
 * cursor seek is worth issuing, the translation of value bounds to index keys, and the max-bound early exhaustion.
 */
public class LmdbStatementIteratorSeekTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();

	@TempDir
	File dataDir;

	private TripleStore tripleStore;
	private ValueStore valueStore;

	private final IRI[] subjects = new IRI[10];
	private final long[] subjectIds = new long[10];
	private IRI predicate;
	private long predicateId;

	@BeforeEach
	public void setUp() throws Exception {
		valueStore = new ValueStore(new File(dataDir, "values"), new LmdbStoreConfig());
		tripleStore = new TripleStore(new File(dataDir, "triples"), new LmdbStoreConfig("spoc,posc"), null);

		predicate = VF.createIRI("http://example.com/p");
		valueStore.startTransaction(true);
		predicateId = valueStore.storeValue(predicate);
		long[] objectIds = new long[10];
		for (int i = 0; i < 10; i++) {
			subjects[i] = VF.createIRI("http://example.com/subject-" + i);
			subjectIds[i] = valueStore.storeValue(subjects[i]);
			objectIds[i] = valueStore.storeValue(VF.createIRI("http://example.com/object-" + i));
		}
		valueStore.commit();

		// the test data relies on insertion order producing ascending ids so that the spoc scan returns
		// subject-0 .. subject-9 in order
		for (int i = 1; i < 10; i++) {
			assertThat(Long.compareUnsigned(subjectIds[i - 1], subjectIds[i])).isLessThan(0);
		}

		tripleStore.startTransaction();
		for (int i = 0; i < 10; i++) {
			tripleStore.storeTriple(subjectIds[i], predicateId, objectIds[i], 0, true);
		}
		tripleStore.commit();
	}

	@AfterEach
	public void tearDown() throws Exception {
		if (tripleStore != null) {
			tripleStore.close();
		}
		if (valueStore != null) {
			valueStore.close();
		}
	}

	private static final class RecordingRecordIterator implements RecordIterator {

		private final RecordIterator delegate;
		private final List<long[]> seekArgs = new ArrayList<>();

		private RecordingRecordIterator(RecordIterator delegate) {
			this.delegate = delegate;
		}

		@Override
		public long[] next() {
			return delegate.next();
		}

		@Override
		public boolean seekForward(long subj, long pred, long obj, long context) {
			seekArgs.add(new long[] { subj, pred, obj, context });
			return delegate.seekForward(subj, pred, obj, context);
		}

		@Override
		public String getIndexName() {
			return delegate.getIndexName();
		}

		@Override
		public void close() {
			delegate.close();
		}
	}

	private RecordingRecordIterator orderedRecordIterator(Txn txn) throws Exception {
		return new RecordingRecordIterator(
				tripleStore.getTriples(txn, StatementOrder.S, -1, predicateId, -1, -1, true));
	}

	private LmdbStatementIterator orderedStatementIterator(RecordingRecordIterator recordIterator) {
		return new LmdbStatementIterator(recordIterator, valueStore, StatementOrder.S, LmdbValue.UNKNOWN_ID,
				predicateId, LmdbValue.UNKNOWN_ID, LmdbValue.UNKNOWN_ID);
	}

	private List<IRI> drainSubjects(LmdbStatementIterator iterator) {
		List<IRI> result = new ArrayList<>();
		while (iterator.hasNext()) {
			Statement statement = iterator.next();
			result.add((IRI) statement.getSubject());
		}
		return result;
	}

	@Test
	public void declinesBelowThresholdThenSeeksOnFourthCall() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			RecordingRecordIterator recording = orderedRecordIterator(txn);
			try (LmdbStatementIterator iterator = orderedStatementIterator(recording)) {
				assertThat(iterator.supportsSeek()).isTrue();
				assertThat(iterator.next().getSubject()).isEqualTo(subjects[0]);

				for (int i = 0; i < 3; i++) {
					iterator.seek(subjects[6], true, null, true);
				}
				assertThat(recording.seekArgs).isEmpty();

				iterator.seek(subjects[6], true, null, true);
				assertThat(recording.seekArgs).hasSize(1);
				assertThat(recording.seekArgs.get(0))
						.containsExactly(subjectIds[6], predicateId, 0L, 0L);

				assertThat(drainSubjects(iterator))
						.containsExactly(subjects[6], subjects[7], subjects[8], subjects[9]);
			}
		}
	}

	@Test
	public void newTargetRestartsTheMissRun() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			RecordingRecordIterator recording = orderedRecordIterator(txn);
			try (LmdbStatementIterator iterator = orderedStatementIterator(recording)) {
				iterator.next();

				for (int i = 0; i < 3; i++) {
					iterator.seek(subjects[3], true, null, true);
				}
				for (int i = 0; i < 3; i++) {
					iterator.seek(subjects[6], true, null, true);
				}
				assertThat(recording.seekArgs).isEmpty();

				iterator.seek(subjects[6], true, null, true);
				assertThat(recording.seekArgs).hasSize(1);
				assertThat(recording.seekArgs.get(0)[TripleIndex.SUBJ_IDX]).isEqualTo(subjectIds[6]);
			}
		}
	}

	@Test
	public void exclusiveMinSeeksPastTheTargetId() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			RecordingRecordIterator recording = orderedRecordIterator(txn);
			try (LmdbStatementIterator iterator = orderedStatementIterator(recording)) {
				iterator.next();

				for (int i = 0; i < 4; i++) {
					iterator.seek(subjects[6], false, null, true);
				}
				assertThat(recording.seekArgs).hasSize(1);
				assertThat(recording.seekArgs.get(0)[TripleIndex.SUBJ_IDX]).isEqualTo(subjectIds[6] + 1);

				assertThat(drainSubjects(iterator)).containsExactly(subjects[7], subjects[8], subjects[9]);
			}
		}
	}

	@Test
	public void inclusiveMaxBoundExhaustsAfterBound() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			RecordingRecordIterator recording = orderedRecordIterator(txn);
			try (LmdbStatementIterator iterator = orderedStatementIterator(recording)) {
				iterator.seek(null, true, subjects[4], true);
				assertThat(drainSubjects(iterator))
						.containsExactly(subjects[0], subjects[1], subjects[2], subjects[3], subjects[4]);
			}
		}
	}

	@Test
	public void exclusiveMaxBoundExhaustsAtBound() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			RecordingRecordIterator recording = orderedRecordIterator(txn);
			try (LmdbStatementIterator iterator = orderedStatementIterator(recording)) {
				iterator.seek(null, true, subjects[4], false);
				assertThat(drainSubjects(iterator))
						.containsExactly(subjects[0], subjects[1], subjects[2], subjects[3]);
			}
		}
	}

	@Test
	public void backwardTargetIsDeclined() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			RecordingRecordIterator recording = orderedRecordIterator(txn);
			try (LmdbStatementIterator iterator = orderedStatementIterator(recording)) {
				for (int i = 0; i < 8; i++) {
					iterator.next();
				}

				for (int i = 0; i < 4; i++) {
					iterator.seek(subjects[3], true, null, true);
				}
				assertThat(recording.seekArgs).isEmpty();

				assertThat(drainSubjects(iterator)).containsExactly(subjects[8], subjects[9]);
			}
		}
	}

	@Test
	public void unresolvableMinValueIsDeclined() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			RecordingRecordIterator recording = orderedRecordIterator(txn);
			try (LmdbStatementIterator iterator = orderedStatementIterator(recording)) {
				iterator.next();

				IRI unknown = VF.createIRI("http://example.com/never-stored");
				for (int i = 0; i < 5; i++) {
					iterator.seek(unknown, true, null, true);
				}
				assertThat(recording.seekArgs).isEmpty();
			}
		}
	}

	@Test
	public void unorderedIteratorNeverSeeks() throws Exception {
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			RecordingRecordIterator recording = new RecordingRecordIterator(
					tripleStore.getTriples(txn, -1, predicateId, -1, -1, true));
			try (LmdbStatementIterator iterator = new LmdbStatementIterator(recording, valueStore)) {
				assertThat(iterator.supportsSeek()).isFalse();
				iterator.next();
				for (int i = 0; i < 5; i++) {
					iterator.seek(subjects[6], true, null, true);
				}
				assertThat(recording.seekArgs).isEmpty();
				assertThat(drainSubjects(iterator)).hasSize(9);
			}
		}
	}

	@Test
	public void systemPropertyDisablesSeek() throws Exception {
		System.setProperty("rdf4j.lmdb.statementSeek.enabled", "false");
		try (Txn txn = tripleStore.getTxnManager().createReadTxn()) {
			RecordingRecordIterator recording = orderedRecordIterator(txn);
			try (LmdbStatementIterator iterator = orderedStatementIterator(recording)) {
				assertThat(iterator.supportsSeek()).isFalse();
				iterator.next();
				for (int i = 0; i < 5; i++) {
					iterator.seek(subjects[6], true, null, true);
				}
				assertThat(recording.seekArgs).isEmpty();
			}
		} finally {
			System.clearProperty("rdf4j.lmdb.statementSeek.enabled");
		}
	}
}
